import { NextFunction, Request, Response } from 'express';

import { WinstonLogger } from '@Libs/WinstonLogger';

import { UnauthorizedError } from '@Errors/UnauthorizedError';
import { ForbiddenError } from '@Errors/ForbiddenError';
import { ErrorCode } from '@Errors/ErrorCode';

const logger = WinstonLogger.create(module);

export function DynamicAPIKeyMiddleware(apiKey: string, headerKey: string) {
  return (req: Request, res: Response, next: NextFunction) => {
    const normalizedHeaderKey = headerKey.toLowerCase();
    const header = req.headers[normalizedHeaderKey] as string;

    logger.info(`DynamicAPIKeyMiddleware:: validating api key in header ${normalizedHeaderKey}`);

    if (!header) {
      throw new UnauthorizedError(ErrorCode.MISSING_API_KEY);
    }

    if (header === apiKey || header.includes(apiKey)) {
      logger.info(`DynamicAPIKeyMiddleware:: api key in header ${normalizedHeaderKey} is valid`);
      return next();
    }

    throw new ForbiddenError(ErrorCode.INVALID_API_KEY);
  };
}

