import { BadRequestError, Body, JsonController, Post, Req, UseBefore } from 'routing-controllers';
import { OpenAPI, ResponseSchema } from 'routing-controllers-openapi';
import { Service } from 'typedi';

import { env } from '@Libs/env';
import { sign, verify } from '@Libs/jwt';

import { JwtTokenType } from '@Enums/JwtTokenType';

import { DynamicAPIKeyMiddleware } from '@Middlewares/rest/DynamicAPIKeyMiddleware';

import { GenerateJwtReq } from '@Rests/types/auth/GenerateJwtReq';
import { GenerateJwtResponse } from '@Rests/types/auth/GenerateJwtResponse';
import { ValidateJwtReq } from '@Rests/types/auth/ValidateJwtReq';

@Service()
@JsonController('/auth')
export class AuthController {
  @Post('/generate')
  @UseBefore(DynamicAPIKeyMiddleware(
    env.auth.generateApiKeyValue,
    env.auth.generateApiKeyHeader || 'x-api-key',
  ))
  @OpenAPI({ summary: 'Generate authentication JWT using JWT_PRIVATE_KEY' })
  @ResponseSchema(GenerateJwtResponse)
  generateJwt(@Body() body: GenerateJwtReq): GenerateJwtResponse {
    if (!env.jwt.privateKey) {
      throw new BadRequestError('JWT_PRIVATE_KEY_MISSING');
    }

    const payload = {
      sub: body.sub,
      roles: body.roles || [],
      tokenType: body.tokenType || JwtTokenType.EXTERNAL_USER_JWT,
      ...(body.claims || {}),
    };

    const token = sign(
      payload,
      env.jwt.privateKey,
      body.expiresIn || '7d',
      { typ: 'JWT', alg: 'RS256' },
      body.issuer,
    );

    return {
      success: true,
      token,
      payload,
      expiresIn: body.expiresIn || '7d',
    };
  }

  @Post('/validate')
  @OpenAPI({ summary: 'Validate external JWT and reuse it for authenticated APIs' })
  validateJwt(@Body() body: ValidateJwtReq, @Req() req: any) {
    const authHeader = req.headers?.authorization || '';
    const [, bearerToken] = authHeader.split(' ');
    const token = body.token || bearerToken;

    if (!token) {
      return {
        valid: false,
        reason: 'TOKEN_MISSING',
      };
    }

    if (!env.jwt.publicKey) {
      return {
        valid: false,
        reason: 'JWT_PUBLIC_KEY_MISSING',
      };
    }

    try {
      const payload = verify(token, env.jwt.publicKey);
      return {
        valid: true,
        token,
        payload,
      };
    } catch (error: any) {
      return {
        valid: false,
        reason: 'TOKEN_INVALID',
        error: error?.message,
      };
    }
  }
}

